/**
 * @param {number} n
 * @param {number[]} prices
 * @param {number[][]} roads
 * @return {number[]}
 */
function solve(n, prices, roads) {
    // --- Step 1: Calculate shortest path costs (Empty Hand) ---
    // We need the shortest path cost from any shop 'j' to any shop 'i' without carrying apples.
    // This is equivalent to finding all-pairs shortest paths on the graph where edge weight is 'cost_i'.
    // Since costs are positive, Dijkstra's algorithm run from every node (or Floyd-Warshall if N were smaller) is suitable.
    // Since N <= 1000, running Dijkstra N times (O(N * (E + N log N))) should be acceptable.

    // Build the graph for empty hand travel (weight = cost)
    const adjEmpty = Array(n).fill(0).map(() => []);
    for (const [u, v, cost, tax] of roads) {
        // Undirected edge
        adjEmpty[u].push({ to: v, weight: cost });
        adjEmpty[v].push({ to: u, weight: cost });
    }

    // distEmpty[j][i] = shortest distance from j to i when empty handed
    const distEmpty = Array(n).fill(0).map(() => Array(n).fill(Infinity));

    // Dijkstra implementation
    const dijkstra = (startNode) => {
        const distances = Array(n).fill(Infinity);
        distances[startNode] = 0;
        // Min-heap stores [distance, node]
        const pq = [[0, startNode]];

        while (pq.length > 0) {
            // Simple priority queue implementation using sort (less efficient but simple for constraints)
            pq.sort((a, b) => a[0] - b[0]);
            const [d, u] = pq.shift();

            if (d > distances[u]) continue;

            for (const edge of adjEmpty[u]) {
                const v = edge.to;
                const weight = edge.weight;
                if (distances[u] + weight < distances[v]) {
                    distances[v] = distances[u] + weight;
                    pq.push([distances[v], v]);
                }
            }
        }
        return distances;
    };

    // Calculate shortest paths from all possible source nodes j (where purchase happens)
    const allDistEmpty = [];
    for (let j = 0; j < n; j++) {
        allDistEmpty.push(dijkstra(j));
    }

    // allDistEmpty[j][i] is the cost from j (purchase location) to i (return location) when empty handed.


    // --- Step 2: Calculate shortest path costs (Carrying Apples) ---
    // We need the shortest path cost from any shop 'i' to any shop 'j' while carrying apples.
    // The weight of the edge (u, v) is cost * tax.
    // Since tax >= 1, the modified costs are non-negative.

    // Build the graph for carrying apples (weight = cost * tax)
    const adjCarrying = Array(n).fill(0).map(() => []);
    for (const [u, v, cost, tax] of roads) {
        const weight = cost * tax;
        // Undirected edge
        adjCarrying[u].push({ to: v, weight: weight });
        adjCarrying[v].push({ to: u, weight: weight });
    }

    // distCarrying[i][j] = shortest distance from i to j when carrying apples
    const distCarrying = Array(n).fill(0).map(() => Array(n).fill(Infinity));

    // Re-use Dijkstra logic, but using adjCarrying
    const dijkstraCarrying = (startNode) => {
        const distances = Array(n).fill(Infinity);
        distances[startNode] = 0;
        const pq = [[0, startNode]];

        while (pq.length > 0) {
            pq.sort((a, b) => a[0] - b[0]);
            const [d, u] = pq.shift();

            if (d > distances[u]) continue;

            for (const edge of adjCarrying[u]) {
                const v = edge.to;
                const weight = edge.weight;
                if (distances[u] + weight < distances[v]) {
                    distances[v] = distances[u] + weight;
                    pq.push([distances[v], v]);
                }
            }
        }
        return distances;
    };

    // Calculate shortest paths from all possible destination nodes i (return location)
    // We need distCarrying[i][j] for the return trip from j to i.
    const allDistCarrying = [];
    for (let i = 0; i < n; i++) {
        allDistCarrying.push(dijkstraCarrying(i));
    }
    // allDistCarrying[i][j] is the cost from i (return location) to j (purchase location) when carrying apples.
    // Since the road is bidirectional, cost(i -> j carrying) = cost(j -> i carrying).
    // We need the cost from J (buy) -> ... -> I (return), so we need distCarrying[J][I].
    // Wait, the problem states: "return ... to shop i". So we go J -> ... -> I, where I=i.
    // The return trip is from J (purchase location) back to I (original shop i).
    // Cost of return trip from J to i carrying apples: distCarrying[J][i].

    // Let's re-read the paths for shop i (target shop):
    // 1. Buy at i: Cost = prices[i]
    // 2. Buy at j, return to i:
    //    Path: i (empty) -> ... -> j (buy) -> ... (carry) -> i (return)
    //    Cost = Path(i -> j, empty) + prices[j] + Path(j -> i, carrying)

    // Path(i -> j, empty): Shortest path from i to j without apples. This is allDistEmpty[i][j].
    // Path(j -> i, carrying): Shortest path from j to i with apples. This is allDistCarrying[j][i].

    // --- Step 3: Calculate minimum cost for each shop i ---
    const ans = Array(n).fill(0);

    for (let i = 0; i < n; i++) {
        // Option 1: Buy at i
        let minCost = prices[i];

        // Option 2: Buy at j (where j != i) and return to i
        for (let j = 0; j < n; j++) {
            if (i === j) continue;

            const dist_i_to_j_empty = allDistEmpty[i][j];
            const dist_j_to_i_carrying = allDistCarrying[j][i];

            if (dist_i_to_j_empty !== Infinity && dist_j_to_i_carrying !== Infinity) {
                // Total Cost = (i -> j empty) + prices[j] + (j -> i carrying)
                const currentCost = dist_i_to_j_empty + prices[j] + dist_j_to_i_carrying;
                minCost = Math.min(minCost, currentCost);
            }
        }
        ans[i] = minCost;
    }

    return ans;
}

