import java.util.*;

class Solution {
    static class Edge {
        int to;
        long weight;

        Edge(int to, long weight) {
            this.to = to;
            this.weight = weight;
        }
    }

    static class State implements Comparable<State> {
        long distance;
        int node;

        State(long distance, int node) {
            this.distance = distance;
            this.node = node;
        }

        @Override
        public int compareTo(State other) {
            return Long.compare(this.distance, other.distance);
        }
    }

    /**
     * Calculates the shortest paths from all nodes to all other nodes using Dijkstra's algorithm.
     *
     * @param n The number of nodes.
     * @param adj The adjacency list representation of the graph.
     * @return A 2D array dist[startNode][endNode] containing the shortest path distances.
     */
    private static long[][] dijkstraAllPairs(int n, List<List<Edge>> adj) {
        long[][] allDist = new long[n][n];
        long INF = Long.MAX_VALUE;

        for (int startNode = 0; startNode < n; startNode++) {
            long[] distances = new long[n];
            Arrays.fill(distances, INF);
            distances[startNode] = 0;

            PriorityQueue<State> pq = new PriorityQueue<>();
            pq.add(new State(0, startNode));

            while (!pq.isEmpty()) {
                State current = pq.poll();
                long d = current.distance;
                int u = current.node;

                if (d > distances[u]) continue;

                for (Edge edge : adj.get(u)) {
                    int v = edge.to;
                    long weight = edge.weight;

                    if (distances[u] != INF && distances[u] + weight < distances[v]) {
                        distances[v] = distances[u] + weight;
                        pq.add(new State(distances[v], v));
                    }
                }
            }
            for (int i = 0; i < n; i++) {
                allDist[startNode][i] = distances[i];
            }
        }
        return allDist;
    }

    public static long[] solve(long nL, long[] pricesL, long[][] roadsL) {
        int n = (int) nL;
        long[] prices = pricesL;
        long[][] roads = roadsL;
        long INF = Long.MAX_VALUE;

        // --- Step 1: Calculate shortest path costs (Empty Hand) ---
        // Edge weight = cost_i
        List<List<Edge>> adjEmpty = new ArrayList<>();
        for (int i = 0; i < n; i++) {
            adjEmpty.add(new ArrayList<>());
        }

        for (long[] road : roads) {
            int u = (int) road[0];
            int v = (int) road[1];
            long cost = road[2];
            // Undirected edge
            adjEmpty.get(u).add(new Edge(v, cost));
            adjEmpty.get(v).add(new Edge(u, cost));
        }

        // allDistEmpty[i][j] = shortest distance from i to j when empty handed
        long[][] allDistEmpty = dijkstraAllPairs(n, adjEmpty);

        // --- Step 2: Calculate shortest path costs (Carrying Apples) ---
        // Edge weight = cost_i * tax_i
        List<List<Edge>> adjCarrying = new ArrayList<>();
        for (int i = 0; i < n; i++) {
            adjCarrying.add(new ArrayList<>());
        }

        for (long[] road : roads) {
            int u = (int) road[0];
            int v = (int) road[1];
            long cost = road[2];
            long tax = road[3];
            long weight = cost * tax;

            // Undirected edge
            adjCarrying.get(u).add(new Edge(v, weight));
            adjCarrying.get(v).add(new Edge(u, weight));
        }

        // allDistCarrying[j][i] = shortest distance from j to i when carrying apples
        long[][] allDistCarrying = dijkstraAllPairs(n, adjCarrying);

        // --- Step 3: Calculate minimum cost for each shop i ---
        long[] ans = new long[n];

        for (int i = 0; i < n; i++) {
            // Option 1: Buy at i
            long minCost = prices[i];

            // Option 2: Buy at j and return to i
            for (int j = 0; j < n; j++) {
                if (i == j) continue;

                // Path: i (empty) -> ... -> j (buy) -> ... (carry) -> i (return)

                // Cost i -> j (empty)
                long dist_i_to_j_empty = allDistEmpty[i][j];

                // Cost j -> i (carrying)
                long dist_j_to_i_carrying = allDistCarrying[j][i];

                if (dist_i_to_j_empty != INF && dist_j_to_i_carrying != INF) {
                    // Total Cost = (i -> j empty) + prices[j] + (j -> i carrying)
                    // Check for overflow before addition, although prices and distances are within long range.
                    // Max distance ~ 1000 * 10^9 * 100 = 10^14. Max price 10^9. Sum fits in long (9*10^18).
                    long currentCost = dist_i_to_j_empty + prices[j] + dist_j_to_i_carrying;
                    minCost = Math.min(minCost, currentCost);
                }
            }
            ans[i] = minCost;
        }

        return ans;
    }
}
