import java.util.*;

public class Solution {

    static class Edge {
        int to;
        long weight;

        Edge(int to, long weight) {
            this.to = to;
            this.weight = weight;
        }
    }

    // Helper function for Dijkstra's algorithm
    private static long[] dijkstra(int n, List<List<Edge>> adj, int startNode) {
        long[] distances = new long[n];
        Arrays.fill(distances, Long.MAX_VALUE);
        distances[startNode] = 0;

        // PriorityQueue stores pairs: [distance, node]
        PriorityQueue<long[]> pq = new PriorityQueue<>(Comparator.comparingLong(a -> a[0]));
        pq.offer(new long[]{0, startNode});

        while (!pq.isEmpty()) {
            long[] current = pq.poll();
            long d = current[0];
            int u = (int) current[1];

            if (d > distances[u]) continue;

            for (Edge edge : adj.get(u)) {
                int v = edge.to;
                long weight = edge.weight;
                if (distances[u] != Long.MAX_VALUE && distances[u] + weight < distances[v]) {
                    distances[v] = distances[u] + weight;
                    pq.offer(new long[]{distances[v], v});
                }
            }
        }
        return distances;
    }

    public static long[] solve(long nLong, long[] prices, long[][] roads) {
        int n = (int) nLong;

