        // Graph where edge weight is 'cost_i'.
        List<List<Edge>> adjEmpty = new ArrayList<>();
        for (int i = 0; i < n; i++) {
            adjEmpty.add(new ArrayList<>());
        }

        for (long[] road : roads) {
            int u = (int) road[0];
            int v = (int) road[1];
            long cost = road[2];
            // tax is not used here

            // Undirected edge
            adjEmpty.get(u).add(new Edge(v, cost));
            adjEmpty.get(v).add(new Edge(u, cost));
        }

        // allDistEmpty[i][j] = shortest distance from i to j when empty handed.
        // We run Dijkstra from every node i.
        long[][] allDistEmpty = new long[n][n];
        for (int i = 0; i < n; i++) {
            long[] dists = dijkstra(n, adjEmpty, i);
            System.arraycopy(dists, 0, allDistEmpty[i], 0, n);
        }

        // --- Step 2: Calculate shortest path costs (Carrying Apples) ---
        // Graph where edge weight is cost * tax.
        List<List<Edge>> adjCarrying = new ArrayList<>();
        for (int i = 0; i < n; i++) {
            adjCarrying.add(new ArrayList<>());
        }

        for (long[] road : roads) {
