import java.util.*;

class Solution {

    // Helper class for priority queue elements
    static class Node implements Comparable<Node> {
        long distance;
        int vertex;

        public Node(long distance, int vertex) {
            this.distance = distance;
            this.vertex = vertex;
        }

        @Override
        public int compareTo(Node other) {
            return Long.compare(this.distance, other.distance);
        }
    }

    /**
     * Runs Dijkstra's algorithm from a start node on a given adjacency list.
     * @param n Number of vertices.
     * @param adj Adjacency list where adj[u] contains pairs of {v, weight}.
     * @param startNode The starting vertex.
     * @return An array of shortest distances from startNode to all other nodes.
     */
    private static long[] dijkstra(int n, List<List<int[]>> adj, int startNode) {
        long[] distances = new long[n];
        Arrays.fill(distances, Long.MAX_VALUE);
        distances[startNode] = 0;

        PriorityQueue<Node> pq = new PriorityQueue<>();
        pq.add(new Node(0, startNode));

        while (!pq.isEmpty()) {
            Node current = pq.poll();
            long d = current.distance;
            int u = current.vertex;

            if (d > distances[u]) continue;

            for (int[] edge : adj.get(u)) {
                int v = edge[0];
                long weight = edge[1];

                if (distances[u] != Long.MAX_VALUE && distances[u] + weight < distances[v]) {
                    distances[v] = distances[u] + weight;
                    pq.add(new Node(distances[v], v));
                }
            }
        }
        return distances;
    }


    public static long[] solve(long nLong, long[] prices, long[][] roads) {
        int n = (int) nLong;

        // --- Step 1: Graph construction and Dijkstra for Empty Hand (Cost = cost_i) ---

        // adjEmpty[u] stores {v, cost}
        List<List<int[]>> adjEmpty = new ArrayList<>(n);
        for (int i = 0; i < n; i++) {
            adjEmpty.add(new ArrayList<>());
        }

        for (long[] road : roads) {
            int u = (int) road[0];
            int v = (int) road[1];
            long cost = road[2];
            // Undirected edge
            adjEmpty.get(u).add(new int[] {v, (int)cost});
            adjEmpty.get(v).add(new int[] {u, (int)cost});
        }

        // allDistEmpty[i][j] = shortest distance from i to j when empty handed
        long[][] allDistEmpty = new long[n][n];
        for (int i = 0; i < n; i++) {
            long[] dists = dijkstra(n, adjEmpty, i);
            System.arraycopy(dists, 0, allDistEmpty[i], 0, n);
        }

        // --- Step 2: Graph construction and Dijkstra for Carrying Apples (Cost = cost_i * tax_i) ---

        // adjCarrying[u] stores {v, cost * tax}
        List<List<int[]>> adjCarrying = new ArrayList<>(n);
        for (int i = 0; i < n; i++) {
            adjCarrying.add(new ArrayList<>());
        }

        for (long[] road : roads) {
            int u = (int) road[0];
            int v = (int) road[1];
            long cost = road[2];
            long tax = road[3];
            long weight = cost * tax;

            // Undirected edge
            // Note: Since weights can exceed Integer.MAX_VALUE (10^9 * 100 = 10^11), 
            // we must use long for weight representation in the graph structure if we were to use a generic Dijkstra.
            // Since the constraints on N are small (N<=1000), using long[][] for distances is fine.
            // However, for the adjacency list to fit the structure, we must cast the weight to int[] element, 
            // which is dangerous if we exceed 2*10^9. Given the constraints, cost*tax fits in long.
            // We will change the structure slightly to handle long weights correctly for carrying graph.
        }

        // Redoing the structure for carrying graph to properly handle long weights
        // adjCarrying[u] stores List<{v, weight}> where weight is long
        List<List<long[]>> adjCarryingLong = new ArrayList<>(n);
        for (int i = 0; i < n; i++) {
            adjCarryingLong.add(new ArrayList<>());
        }

        for (long[] road : roads) {
            int u = (int) road[0];
            int v = (int) road[1];
            long cost = road[2];
            long tax = road[3];
            long weight = cost * tax;

            // Undirected edge: {v, weight}
            adjCarryingLong.get(u).add(new long[] {(long)v, weight});
            adjCarryingLong.get(v).add(new long[] {(long)u, weight});
