     * @param n Number of vertices.
     * @param adj Adjacency list where adj[u] contains pairs of {v, weight}.
     * @param startNode The starting vertex.
     * @return An array of shortest distances from startNode to all other nodes.
     */
    private static long[] dijkstra(int n, List<List<int[]>> adj, int startNode) {
        long[] distances = new long[n];
        Arrays.fill(distances, Long.MAX_VALUE);
        distances[startNode] = 0;

        PriorityQueue<Node> pq = new PriorityQueue<>();
        pq.add(new Node(0, startNode));

