    // We need the shortest path cost from any shop 'i' to any shop 'j' while carrying apples.
    // The weight of the edge (u, v) is cost * tax.
    // Since tax >= 1, the modified costs are non-negative.

    // Build the graph for carrying apples (weight = cost * tax)
    const adjCarrying = Array(n).fill(0).map(() => []);
    for (const [u, v, cost, tax] of roads) {
